// Study guide content mapped to syllabusData chapter IDs
// Every chapter from syllabusData MUST have an entry here

export interface ChapterStudyContent {
  keyConcepts: string[];
  formulas?: string[];
  books: string[];
  tip: string;
}

// Default content for chapters without detailed guide yet
const defaultContent = (name: string, subject: string, cls: string): ChapterStudyContent => ({
  keyConcepts: [`Read NCERT Class ${cls} ${subject} — ${name} chapter thoroughly`, `Solve all in-text questions and back exercises`, `Make short notes with diagrams for revision`],
  books: [`NCERT Class ${cls} ${subject}`],
  tip: `Focus on NCERT first. Solve previous year questions from this chapter.`,
});

