  'phy-11': { keyConcepts: ['Wave equation: y=Asin(kx-ωt)', 'Speed: v=fλ=ω/k', 'Transverse vs Longitudinal waves', 'Superposition, Standing waves, Harmonics', 'String: fn=n(v/2L), Pipe: Open(all harmonics), Closed(odd only)', 'Beats: fbeat=|f₁-f₂|', 'Doppler effect for sound'], formulas: ['v=fλ', 'v=√(T/μ)', 'fbeat=|f₁-f₂|'], books: ['NCERT 11 Ch.15'], tip: 'Standing waves in strings/pipes formulas. Doppler effect problems. Beats concept.' },
