  'phy-14': { keyConcepts: ['Ohm\'s law: V=IR', 'Resistance: R=ρL/A, Resistivity depends on material', 'Kirchhoff\'s laws: Junction(ΣI=0), Loop(ΣV=0)', 'Wheatstone bridge: balanced when P/Q=R/S', 'Meter bridge, Potentiometer principle', 'EMF vs Terminal voltage: V=E-Ir', 'Power: P=VI=I²R=V²/R'], formulas: ['V=IR', 'R=ρL/A', 'P=I²R'], books: ['NCERT 12 Ch.3', 'HC Verma'], tip: 'HIGHEST scoring Physics chapter for NEET (3-4 questions). Kirchhoff + Wheatstone + Potentiometer.' },
  'phy-15': { keyConcepts: ['Biot-Savart law: dB=μ₀Idl×r/4πr³', 'B at center of circular loop: B=μ₀nI/2R', 'Ampere\'s law: ∮B·dl=μ₀I', 'Solenoid: B=μ₀nI', 'Force on current: F=BIl sinθ', 'Force between parallel wires: F/L=μ₀I₁I₂/2πd', 'Torque on current loop: τ=NBIA sinθ'], formulas: ['F=BIl', 'B=μ₀nI', 'τ=NBIA sinθ'], books: ['NCERT 12 Ch.4'], tip: 'Biot-Savart + Ampere\'s law applications. Force on current-carrying conductor.' },
