  'phy-23': { keyConcepts: ['Intrinsic semiconductor: pure Si/Ge, equal e⁻ and holes', 'Extrinsic: n-type(P, As doping), p-type(B, Al doping)', 'p-n junction diode: Forward bias(current flows), Reverse bias(no current)', 'Zener diode: voltage regulator', 'Transistor: npn/pnp, CE amplifier, gain β=Ic/Ib', 'Logic gates: AND, OR, NOT, NAND, NOR'], books: ['NCERT 12 Ch.14'], tip: 'p-n junction + Transistor basics. Logic gates truth tables. Usually 2 questions.' },
